class Solution:
    def maximumXOR(self, nums):
        bits = set()
        for v in nums:
            b = 0
            while v:
                if v & 1:
                    bits.add(b)
                v >>= 1
                b += 1
        result = 0
        for b in bits:
            result |= (1 << b)
        return result

